patch:
--- src/scene/mesh/shared/MeshGeometry.ts
+++ src/scene/mesh/shared/MeshGeometry.ts
@@ -114,6 +114,7 @@
     constructor(...args: [MeshGeometryOptions] | [Float32Array, Float32Array, Uint32Array])
     {
         let options = args[0] ?? {};

+        this._positionBuffer = null;
+        this._uvBuffer = null;
+        this._indexBuffer = null;

         if (options instanceof Float32Array)
         {
             // #if _DEBUG
@@ -154,7 +155,7 @@
         const positionBuffer = new Buffer({
             data: positions,
             label: 'attribute-mesh-positions',
-            shrinkToFit,
+            true, // always shrink to fit
             usage: BufferUsage.VERTEX | BufferUsage.COPY_DST,
         });

@@ -163,7 +164,7 @@
         const uvBuffer = new Buffer({
             data: uvs,
             label: 'attribute-mesh-uvs',
-            shrinkToFit,
+            true, // always shrink to fit
             usage: BufferUsage.VERTEX | BufferUsage.COPY_DST,
         });

@@ -172,7 +173,7 @@
         const indexBuffer = new Buffer({
             data: indices,
             label: 'index-mesh-buffer',
-            shrinkToFit,
+            true, // always shrink to fit
             usage: BufferUsage.INDEX | BufferUsage.COPY_DST,
         });

@@ -184,6 +185,10 @@
         super({
             attributes: {
                 aPosition: {
+                    buffer: this._positionBuffer = positionBuffer,
                     format: 'float32x2',
                     stride: 2 * 4,
                     offset: 0,
@@ -193,6 +198,10 @@
                 aUV: {
+                    buffer: this._uvBuffer = uvBuffer,
                     format: 'float32x2',
                     stride: 2 * 4,
                     offset: 0,
@@ -202,6 +211,9 @@
             indexBuffer: this._indexBuffer = indexBuffer,
             topology: options.topology,
         });
+        this.updateBuffers();
     }

+    private updateBuffers(): void
+    {
+        if (this._positionBuffer) this._positionBuffer.resize(this.positions.length * 4);
+        if (this._uvBuffer) this._uvBuffer.resize(this.uvs.length * 4);
+        if (this._indexBuffer) this._indexBuffer.resize(this.indices.length * 4);
+    }

     /** The positions of the mesh. */
     get positions(): Float32Array
@@ -220,6 +232,7 @@
     set positions(value: Float32Array)
     {
         this.attributes.aPosition.buffer.data = value;
+        this.updateBuffers();
     }

     /** The UVs of the mesh. */
@@ -228,6 +241,7 @@
     set uvs(value: Float32Array)
     {
         this.attributes.aUV.buffer.data = value;
+        this.updateBuffers();
     }

     /** The indices of the mesh. */
@@ -236,6 +250,7 @@
     set indices(value: Uint32Array)
     {
         this.indexBuffer.data = value;
+        this.updateBuffers();
     }
